class Solution:
    def findTheLongestSubstring(self, s: str) -> int:

        state_map = {0: -1}
        vowels = {'a': 0, 'e': 1, 'i': 2, 'o': 3, 'u': 4}
        max_len = 0
        mask = 0

        for i, ch in enumerate(s):
            if ch in vowels:
                mask ^= (1 << vowels[ch])
            if mask in state_map:
                max_len = max(max_len, i - state_map[mask])
            else:
                state_map[mask] = i

        return max_len

